    #{id}, #{consumerGroup}, #{eventId}, #{topic}, #{eventType}, #{bizKey}, #{envelopeJson}, #{consumeStatus},
    #{retryCount}, #{errorMessage}, #{consumedAt}, #{createdAt}, #{updatedAt}
