mapper.select:
SELECT id, consumer_group, event_id, topic, event_type, biz_key, envelope_json, consume_status,
       retry_count, error_message, consumed_at, created_at, updated_at
FROM bluenote_notification.notification_consume_record
WHERE consumer_group = #{consumerGroup}
  AND event_id = #{eventId}

mapper.update:
UPDATE bluenote_notification.notification_consume_record
SET consume_status = 'SUCCESS',
    error_message = NULL,
    consumed_at = #{consumedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE bluenote_notification.notification_consume_record
SET consume_status = 'SKIPPED',
    error_message = #{reason},
    consumed_at = #{consumedAt},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE bluenote_notification.notification_consume_record
SET consume_status = 'FAIL',
    retry_count = retry_count + 1,
    error_message = #{errorMessage},
    updated_at = #{updatedAt}
WHERE id = #{id}
